return $input.all().map((item, index) => {
  const sanitizeText = (value) => {
    return String(value ?? '')
      .replace(/[“”]/g, '"')
      .replace(/[‘’]/g, "'")
      .replace(/[＂]/g, '"')
      .replace(/[＇]/g, "'")
      .replace(/[「」]/g, '"')
      .replace(/[『』]/g, '"')
      .replace(/[‚‛]/g, "'")
      .replace(/[„‟]/g, '"')
      .replace(/\u00A0/g, ' ')
      .replace(/\u2028/g, ' ')
      .replace(/\u2029/g, ' ')
      .replace(/\r\n/g, '\n')
      .replace(/\r/g, '\n')
      .trim();
  };

  const stripHtml = (html) => {
    return sanitizeText(html)
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
      .replace(/<[^>]*>/g, ' ')
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#34;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/&apos;/g, "'")
      .replace(/\s+/g, ' ')
      .trim();
  };

  const firstText = (...values) => {
    for (const value of values) {
      const text = sanitizeText(value);
      if (text) return text;
    }
    return '';
  };

  const firstValue = (...values) => {
    for (const value of values) {
      if (value !== undefined && value !== null && value !== '') return value;
    }
    return '';
  };

  const toBool = (value) => {
    if (value === true) return true;
    if (value === false) return false;
    if (String(value).toLowerCase() === 'true') return true;
    if (String(value).toLowerCase() === 'false') return false;
    return Boolean(value);
  };

  const sourceFromUrl = (url) => {
    const text = String(url || '').toLowerCase();

    if (text.includes('openai.com')) return 'OpenAI';
    if (text.includes('anthropic.com')) return 'Anthropic';
    if (text.includes('deepmind')) return 'Google DeepMind';
    if (text.includes('google')) return 'Google';
    if (text.includes('microsoft.com')) return 'Microsoft';
    if (text.includes('github.com')) return 'GitHub';
    if (text.includes('huggingface.co')) return 'Hugging Face';
    if (text.includes('nvidia.com')) return 'NVIDIA';
    if (text.includes('marktechpost.com')) return 'MarkTechPost';
    if (text.includes('vercel.com')) return 'Vercel';
    if (text.includes('sakana.ai')) return 'Sakana AI';

    return '';
  };

  const makeArticleId = (data, fallbackIndex) => {
    const base =
      data.article_id ||
      data.guid ||
      data.id ||
      data.link ||
      data.url ||
      data.rssUrl ||
      data.title ||
      'article_' + fallbackIndex;

    return String(base)
      .trim()
      .toLowerCase()
      .replace(/[?#].*$/, '')
      .replace(/\/$/, '');
  };

  const current = item.json || {};

  let original = {};
  let pmItem = {};

  try {
    original = $('Code').all()[index]?.json || {};
  } catch (e) {
    original = {};
  }

  try {
    pmItem = $('Code in JavaScript6').all()[index]?.json || {};
  } catch (e) {
    pmItem = {};
  }

  const merged = {
    ...original,
    ...pmItem,
    ...current
  };

  const html =
    current.data ||
    current.body ||
    current.html ||
    current.response ||
    current.content ||
    current.result ||
    merged.data ||
    merged.body ||
    merged.html ||
    merged.response ||
    merged.content ||
    merged.result ||
    '';

  const text = sanitizeText(stripHtml(html)).slice(0, 12000);

  const title = firstText(
    current.title,
    current.name,
    current.headline,
    merged.title,
    merged.name,
    merged.headline,
    pmItem.title,
    original.title
  );

  const description = firstText(
    current.description,
    current.summary,
    current.excerpt,
    merged.description,
    merged.summary,
    merged.excerpt,
    pmItem.description,
    pmItem.summary,
    original.description,
    original.summary
  );

  const link = firstText(
    current.link,
    current.url,
    current.href,
    merged.link,
    merged.url,
    merged.href,
    pmItem.link,
    pmItem.url,
    original.link,
    original.url
  );

  const rssUrl = firstText(
    current.rssUrl,
    current.rss_url,
    current.feedUrl,
    current.feed_url,
    merged.rssUrl,
    merged.rss_url,
    merged.feedUrl,
    merged.feed_url,
    pmItem.rssUrl,
    pmItem.rss_url,
    pmItem.feedUrl,
    pmItem.feed_url,
    original.rssUrl,
    original.rss_url,
    original.feedUrl,
    original.feed_url
  );

  const pubDate = firstText(
    current.pubDate,
    current.published,
    current.updated,
    current.isoDate,
    merged.pubDate,
    merged.published,
    merged.updated,
    merged.isoDate,
    pmItem.pubDate,
    pmItem.published,
    pmItem.updated,
    pmItem.isoDate,
    original.pubDate,
    original.published,
    original.updated,
    original.isoDate
  );

  const source = firstText(
    current.source,
    current.feed_source,
    current.feedTitle,
    current.publisher,
    current.site_name,

    sourceFromUrl(current.link || current.url || current.href),
    sourceFromUrl(current.rssUrl || current.rss_url || current.feedUrl || current.feed_url),

    merged.source,
    merged.feed_source,
    merged.feedTitle,
    merged.publisher,
    merged.site_name,

    sourceFromUrl(link),
    sourceFromUrl(rssUrl),

    pmItem.source,
    pmItem.feed_source,
    pmItem.feedTitle,
    pmItem.publisher,
    pmItem.site_name,

    original.source,
    original.feed_source,
    original.feedTitle,
    original.publisher,
    original.site_name
  );

  const category = firstText(
    current.category,
    current.categories,
    merged.category,
    merged.categories,
    pmItem.category,
    pmItem.categories,
    original.category,
    original.categories
  );

  const pm_score = firstValue(
    current.pm_score,
    current.pmScore,
    current.score,
    current.importance_score,
    merged.pm_score,
    merged.pmScore,
    merged.score,
    merged.importance_score,
    pmItem.pm_score,
    pmItem.pmScore,
    pmItem.score,
    pmItem.importance_score,
    original.pm_score,
    original.pmScore,
    original.score,
    original.importance_score
  );

  const pm_reason = firstText(
    current.pm_reason,
    current.pmReason,
    current.reason,
    current.importance_reason,
    merged.pm_reason,
    merged.pmReason,
    merged.reason,
    merged.importance_reason,
    pmItem.pm_reason,
    pmItem.pmReason,
    pmItem.reason,
    pmItem.importance_reason,
    original.pm_reason,
    original.pmReason,
    original.reason,
    original.importance_reason
  );

  const pm_action = firstText(
    current.pm_action,
    current.pmAction,
    current.action,
    current.reason_to_skip_or_read,
    merged.pm_action,
    merged.pmAction,
    merged.action,
    merged.reason_to_skip_or_read,
    pmItem.pm_action,
    pmItem.pmAction,
    pmItem.action,
    pmItem.reason_to_skip_or_read,
    original.pm_action,
    original.pmAction,
    original.action,
    original.reason_to_skip_or_read
  );

  const should_deep_analyze = toBool(
    firstValue(
      current.should_deep_analyze,
      merged.should_deep_analyze,
      pmItem.should_deep_analyze,
      original.should_deep_analyze,
      Number(pm_score || 0) >= 3
    )
  );

  const article_id = makeArticleId(
    {
      ...merged,
      ...current,
      title,
      link,
      rssUrl
    },
    index
  );

  const stage2FormatSchema = {
    type: 'object',
    properties: {
      analysis_meta: {
        type: 'object',
        properties: {
          analysis_fit: {
            type: 'string',
            enum: ['high', 'medium', 'low']
          },
          evidence_level: {
            type: 'string',
            enum: ['高', '中', '低']
          },
          data_quality: {
            type: 'string'
          },
          one_sentence_judgment: {
            type: 'string'
          },
          summary_cn: {
            type: 'string'
          },
          should_be_main_report: {
            type: 'boolean'
          },
          reason_if_not_main_report: {
            type: 'string'
          }
        },
        required: [
          'analysis_fit',
          'evidence_level',
          'data_quality',
          'one_sentence_judgment',
          'summary_cn',
          'should_be_main_report',
          'reason_if_not_main_report'
        ]
      },
      narrative_report: {
        type: 'object',
        properties: {
          overview: {
            type: 'string'
          },
          why_it_matters: {
            type: 'string'
          },
          product_implication: {
            type: 'string'
          },
          business_or_strategy_signal: {
            type: 'string'
          },
          risk_and_limits: {
            type: 'string'
          },
          pm_takeaway: {
            type: 'string'
          },
          caution: {
            type: 'string'
          }
        },
        required: [
          'overview',
          'why_it_matters',
          'product_implication',
          'business_or_strategy_signal',
          'risk_and_limits',
          'pm_takeaway',
          'caution'
        ]
      },
      compact_signals: {
        type: 'object',
        properties: {
          product_signal: {
            type: 'string'
          },
          competitive_signal: {
            type: 'string'
          },
          enterprise_adoption_signal: {
            type: 'string'
          },
          agent_or_workflow_signal: {
            type: 'string'
          },
          pricing_or_distribution_signal: {
            type: 'string'
          }
        },
        required: [
          'product_signal',
          'competitive_signal',
          'enterprise_adoption_signal',
          'agent_or_workflow_signal',
          'pricing_or_distribution_signal'
        ]
      },
      pm_actions: {
        type: 'array',
        items: {
          type: 'string'
        },
        minItems: 2
      },
      what_to_watch: {
        type: 'array',
        items: {
          type: 'string'
        },
        minItems: 3
      }
    },
    required: [
      'analysis_meta',
      'narrative_report',
      'compact_signals',
      'pm_actions',
      'what_to_watch'
    ]
  };

  let prompt_stage2 = `
/no_think

你是 AI 产品经理和企业 AI 落地分析师。

任务：
基于给定的 RSS 摘要和文章正文，生成一份面向 AI 产品经理的中文深度分析。

硬性规则：
1. 只使用输入材料中的信息，不要补充正文之外的背景知识。
2. 不要把普通客户案例、课程、品牌宣传、普通合作新闻夸大成战略事件。
3. 如果正文没有披露某项信息，必须写“正文未披露”。
4. 如果标题、摘要、正文、链接明显不一致，必须在 data_quality 和 caution 中说明。
5. 所有推断必须写成“基于正文可推断……”，不要写成确定事实。
6. 只输出合法 JSON，不要 Markdown，不要代码块，不要解释。
7. 字段名必须使用英文，字段值必须使用简体中文。
8. 不要输出英文句子，专有名词如 OpenAI、API、SDK、Agent、Workflow、Copilot 可以保留。
9. 每个字段都必须有内容，不允许空字符串。
10. 必须把 RSS 摘要翻译成简体中文，写入 analysis_meta.summary_cn；只翻译摘要本身，不要加入正文外信息。
11. pm_actions 至少 2 条，what_to_watch 至少 3 条；信息不足时写“正文未披露，建议人工核查”。

评分参考：
- high：正文披露了明确的新产品能力、平台机制、Agent/Workflow 能力、企业部署路径、安全治理机制、商业化变化或竞品动作。
- medium：正文有一定产品、场景、企业采用或技术路线参考价值，但缺少足够机制细节。
- low：正文主要是教程、宣传、普通案例、泛泛观点，难以支持产品判断。

已有 PM 初筛信息：
pm_score：${pm_score}
pm_reason：${pm_reason}
pm_action：${pm_action}
should_deep_analyze：${should_deep_analyze}

输入材料：
标题：${title}
来源：${source}
发布时间：${pubDate}
链接：${link}
RSS URL：${rssUrl}
RSS 摘要：${description}

文章正文：
${text}

输出要求：
请严格输出一个 JSON 对象，不要输出 JSON 之外的任何内容。

JSON 结构如下：

{
  "analysis_meta": {
    "analysis_fit": "high | medium | low",
    "evidence_level": "高 | 中 | 低",
    "data_quality": "说明正文信息是否足够、是否存在标题摘要正文链接不一致",
    "one_sentence_judgment": "一句话判断本文对 AI 产品经理的价值",
    "summary_cn": "将 RSS 摘要忠实翻译成简体中文，不添加摘要外信息；如果原摘要已经是中文，则润色为自然中文",
    "should_be_main_report": true,
    "reason_if_not_main_report": "如果适合进入主报告，写适合进入主报告；否则说明原因"
  },
  "narrative_report": {
    "overview": "80-160字，说明文章讲了什么，核心变化是什么",
    "why_it_matters": "80-160字，解释为什么值得关注，必须引用正文中的具体机制、场景或事实",
    "product_implication": "80-160字，说明对产品设计、路线、评估、上线流程或用户体验的启发",
    "business_or_strategy_signal": "80-140字，说明商业、生态、渠道、企业采用或战略信号",
    "risk_and_limits": "80-140字，说明为什么不能高估，以及正文未披露什么",
    "pm_takeaway": "80-140字，给 AI 产品经理的具体结论",
    "caution": "说明是否需要人工核查链接、正文和标题一致性"
  },
  "compact_signals": {
    "product_signal": "一句话总结产品信号；没有则写无明显产品信号",
    "competitive_signal": "一句话总结竞品或生态信号；没有则写无明显竞品信号",
    "enterprise_adoption_signal": "一句话总结企业采用、部署、治理或采购信号；没有则写无明显企业采用信号",
    "agent_or_workflow_signal": "一句话总结 Agent、Workflow、Copilot 或自动化启发；没有则写无明显 Agent 或 Workflow 信号",
    "pricing_or_distribution_signal": "一句话总结定价、渠道、分发或商业模式启发；没有则写无明显定价或分发信号"
  },
  "pm_actions": [
    "一个具体、可执行的 AI 产品经理动作建议",
    "第二个具体、可执行的 AI 产品经理动作建议"
  ],
  "what_to_watch": [
    "一个具体后续关注点",
    "第二个具体后续关注点",
    "第三个具体后续关注点"
  ]
}
`;

  prompt_stage2 = sanitizeText(prompt_stage2);

  return {
    json: {
      article_id,

      title,
      description,
      url: link,
      link,
      category,
      pubDate,
      source,
      rssUrl,

      pm_score,
      pm_reason,
      pm_action,
      should_deep_analyze,

      text,

      prompt_stage2,

      ollama_stage2_body: {
        model: 'qwen3:8b',
        prompt: prompt_stage2,
        stream: false,
        think: false,
        format: stage2FormatSchema,
        options: {
          temperature: 0.2,
          top_p: 0.9,
          repeat_penalty: 1.1
        }
      }
    }
  };
});

var DOUBLE_QUOTE = String.fromCharCode(34);
var SINGLE_QUOTE = String.fromCharCode(39);

// 日期筛选使用的时区
// 英国伦敦时区，会自动处理夏令时
var FILTER_TIME_ZONE = 'Europe/London';

// 最近多少天，包含今天
// 7 表示今天以及之前 6 天
var FILTER_DAYS = 7;

// 最多输出多少篇文章
var MAX_OUTPUT_COUNT = 20;

var source = '';
var rssUrl = '';

if ($json.source !== undefined && $json.source !== null) {
  source = String($json.source).trim();
}

if ($json.rssUrl !== undefined && $json.rssUrl !== null) {
  rssUrl = String($json.rssUrl).trim();
} else if ($json.rss_url !== undefined && $json.rss_url !== null) {
  rssUrl = String($json.rss_url).trim();
} else if ($json.url !== undefined && $json.url !== null) {
  rssUrl = String($json.url).trim();
}

var rssData = $json;

if ($json.rss_response !== undefined && $json.rss_response !== null) {
  rssData = $json.rss_response;
}

var items = [];

if (
  rssData.rss &&
  rssData.rss.channel &&
  rssData.rss.channel.item
) {
  if (Array.isArray(rssData.rss.channel.item)) {
    items = rssData.rss.channel.item;
  } else {
    items = [rssData.rss.channel.item];
  }
}

if (
  items.length === 0 &&
  rssData.feed &&
  rssData.feed.entry
) {
  if (Array.isArray(rssData.feed.entry)) {
    items = rssData.feed.entry;
  } else {
    items = [rssData.feed.entry];
  }
}

if (
  items.length === 0 &&
  rssData.feed &&
  rssData.feed.channel &&
  rssData.feed.channel.item
) {
  if (Array.isArray(rssData.feed.channel.item)) {
    items = rssData.feed.channel.item;
  } else {
    items = [rssData.feed.channel.item];
  }
}

function toText(value) {
  if (value === undefined || value === null) {
    return '';
  }

  if (typeof value === 'string') {
    return value.trim();
  }

  if (typeof value === 'number') {
    return String(value);
  }

  if (typeof value === 'boolean') {
    return String(value);
  }

  if (Array.isArray(value)) {
    if (value.length === 0) {
      return '';
    }

    return toText(value[0]);
  }

  if (typeof value === 'object') {
    if (value._ !== undefined && value._ !== null) {
      return String(value._).trim();
    }

    if (value['#text'] !== undefined && value['#text'] !== null) {
      return String(value['#text']).trim();
    }

    if (value.href !== undefined && value.href !== null) {
      return String(value.href).trim();
    }

    if (value.term !== undefined && value.term !== null) {
      return String(value.term).trim();
    }

    if (value.value !== undefined && value.value !== null) {
      return toText(value.value);
    }

    if (value.content !== undefined && value.content !== null) {
      return toText(value.content);
    }
  }

  return '';
}

function cleanHtml(value) {
  var text = String(value || '');

  text = text.replace(/<[^>]*>/g, ' ');
  text = text.replace(/&nbsp;/g, ' ');
  text = text.replace(/&amp;/g, '&');
  text = text.replace(/&lt;/g, '<');
  text = text.replace(/&gt;/g, '>');
  text = text.replace(/&quot;/g, DOUBLE_QUOTE);
  text = text.replace(/&#34;/g, DOUBLE_QUOTE);
  text = text.replace(/&#39;/g, SINGLE_QUOTE);
  text = text.replace(/&apos;/g, SINGLE_QUOTE);

  text = text.replace(/“/g, DOUBLE_QUOTE);
  text = text.replace(/”/g, DOUBLE_QUOTE);
  text = text.replace(/‘/g, SINGLE_QUOTE);
  text = text.replace(/’/g, SINGLE_QUOTE);
  text = text.replace(/`/g, SINGLE_QUOTE);
  text = text.replace(/…/g, '...');

  while (text.indexOf('  ') >= 0) {
    text = text.split('  ').join(' ');
  }

  return text.trim();
}

function getLink(item) {
  var i;
  var oneLink;
  var linkValue;

  if (!item) {
    return '';
  }

  if (typeof item.link === 'string') {
    return item.link.trim();
  }

  if (Array.isArray(item.link)) {
    for (i = 0; i < item.link.length; i++) {
      oneLink = item.link[i];

      if (
        typeof oneLink === 'string' &&
        oneLink.trim()
      ) {
        return oneLink.trim();
      }

      if (oneLink && oneLink.href) {
        return String(oneLink.href).trim();
      }

      if (oneLink && oneLink._) {
        return String(oneLink._).trim();
      }

      if (oneLink && oneLink['#text']) {
        return String(oneLink['#text']).trim();
      }
    }
  }

  if (item.link && item.link.href) {
    return String(item.link.href).trim();
  }

  if (item.link && item.link._) {
    return String(item.link._).trim();
  }

  if (item.link && item.link['#text']) {
    return String(item.link['#text']).trim();
  }

  if (typeof item.guid === 'string') {
    return item.guid.trim();
  }

  if (item.guid && item.guid._) {
    return String(item.guid._).trim();
  }

  if (item.guid && item.guid['#text']) {
    return String(item.guid['#text']).trim();
  }

  if (item.id) {
    linkValue = toText(item.id);

    if (linkValue) {
      return linkValue;
    }
  }

  return '';
}

function getCategory(item) {
  var result = [];
  var i;
  var one;
  var text;

  if (
    !item ||
    item.category === undefined ||
    item.category === null
  ) {
    return '';
  }

  if (typeof item.category === 'string') {
    return item.category.trim();
  }

  if (Array.isArray(item.category)) {
    for (i = 0; i < item.category.length; i++) {
      one = item.category[i];
      text = toText(one);

      if (text) {
        result.push(text);
      }
    }

    return result.join(',');
  }

  return toText(item.category);
}

function getDomain(url) {
  var text = String(url || '').trim().toLowerCase();
  var slashIndex;

  if (text.indexOf('https://') === 0) {
    text = text.slice(8);
  }

  if (text.indexOf('http://') === 0) {
    text = text.slice(7);
  }

  if (text.indexOf('www.') === 0) {
    text = text.slice(4);
  }

  slashIndex = text.indexOf('/');

  if (slashIndex >= 0) {
    text = text.slice(0, slashIndex);
  }

  return text;
}

