function makeArticleId(link, title, index) {
  var id = String(
    link ||
    title ||
    'article_' + index
  ).trim().toLowerCase();

  var questionIndex = id.indexOf('?');
  var hashIndex = id.indexOf('#');

  if (questionIndex >= 0) {
    id = id.slice(0, questionIndex);
  }

  if (hashIndex >= 0) {
    id = id.slice(0, hashIndex);
  }

  while (
    id.length > 1 &&
    id.charAt(id.length - 1) === '/'
  ) {
    id = id.slice(0, -1);
  }

  return id;
}

/**
 * 把 Date 转换为指定时区的 YYYY-MM-DD。
 */
function getDateKey(date, timeZone) {
  if (
    !(date instanceof Date) ||
    isNaN(date.getTime())
  ) {
    return '';
  }

  var formatter = new Intl.DateTimeFormat('en-CA', {
    timeZone: timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  });

  var parts = formatter.formatToParts(date);
  var year = '';
  var month = '';
  var day = '';

  for (var i = 0; i < parts.length; i++) {
    if (parts[i].type === 'year') {
      year = parts[i].value;
    } else if (parts[i].type === 'month') {
      month = parts[i].value;
    } else if (parts[i].type === 'day') {
      day = parts[i].value;
    }
  }

  if (!year || !month || !day) {
    return '';
  }

  return year + '-' + month + '-' + day;
}

/**
 * 把 YYYY-MM-DD 转成 UTC 零点时间戳。
 * 用于比较日期差，避免夏令时影响。
 */
function dateKeyToUtcTimestamp(dateKey) {
  var match = String(dateKey || '').match(
    /^(\d{4})-(\d{2})-(\d{2})$/
  );

  if (!match) {
    return null;
  }

  return Date.UTC(
    Number(match[1]),
    Number(match[2]) - 1,
    Number(match[3])
  );
}

/**
 * 根据 YYYY-MM-DD 计算若干天前的日期。
 */
function getPreviousDateKey(dateKey, daysBack) {
  var timestamp = dateKeyToUtcTimestamp(dateKey);

  if (timestamp === null) {
    return '';
  }

  var date = new Date(timestamp);

  date.setUTCDate(
    date.getUTCDate() - Number(daysBack || 0)
  );

  var year = String(date.getUTCFullYear());
  var month = String(date.getUTCMonth() + 1);
  var day = String(date.getUTCDate());

  if (month.length < 2) {
    month = '0' + month;
  }

  if (day.length < 2) {
    day = '0' + day;
  }

  return year + '-' + month + '-' + day;
}

/**
 * 解析 RSS 发布时间。
 */
function parsePublishDate(value) {
  var text = String(value || '').trim();

  if (!text) {
    return null;
  }

  // 10 位 Unix 秒时间戳
  if (/^\d{10}$/.test(text)) {
    var secondsDate = new Date(
      Number(text) * 1000
    );

    if (!isNaN(secondsDate.getTime())) {
      return secondsDate;
    }

    return null;
  }

  // 13 位 Unix 毫秒时间戳
  if (/^\d{13}$/.test(text)) {
    var millisecondsDate = new Date(
      Number(text)
    );

    if (!isNaN(millisecondsDate.getTime())) {
      return millisecondsDate;
    }

    return null;
  }

  var parsedDate = new Date(text);

  if (isNaN(parsedDate.getTime())) {
    return null;
  }

  return parsedDate;
}

/**
 * 判断文章是否在最近指定天数内。
 *
 * days = 7 时：
 * 今天日期差为 0；
 * 昨天日期差为 1；
 * 最早接受日期差为 6。
 */
function isWithinLastDays(pubDate, timeZone, days) {
  var publishedDate = parsePublishDate(pubDate);

  if (!publishedDate) {
    return false;
  }

  var todayKey = getDateKey(
    new Date(),
    timeZone
  );

  var publishedKey = getDateKey(
    publishedDate,
    timeZone
  );

  var todayTimestamp =
    dateKeyToUtcTimestamp(todayKey);

  var publishedTimestamp =
    dateKeyToUtcTimestamp(publishedKey);

  if (
    todayTimestamp === null ||
    publishedTimestamp === null
  ) {
    return false;
  }

  var oneDayMilliseconds =
    24 * 60 * 60 * 1000;

  var differenceInDays = Math.floor(
    (todayTimestamp - publishedTimestamp) /
    oneDayMilliseconds
  );

  return (
    differenceInDays >= 0 &&
    differenceInDays < days
  );
}

