function buildOutputItem(
  article,
  filterMode,
  totalItems,
  selectedCount,
  todayKey,
  rangeStartKey
) {
  var parsedDate = parsePublishDate(
    article.pubDate
  );

  return {
    json: {
      article_id: article.article_id,
      title: article.title,
      description: article.description,
      link: article.link,
      url: article.url,
      category: article.category,
      pubDate: article.pubDate,
      source: article.source,
      rssUrl: article.rssUrl,

      pm_score_prompt: buildPmPrompt(article),

      // last_7_days：
      // 最近 7 天内有文章
      //
      // latest_fallback：
      // 最近 7 天没有文章，回退到最近 20 篇
      article_filter_mode: filterMode,

      is_recent_date_match:
        filterMode === 'last_7_days',

      used_latest_fallback:
        filterMode === 'latest_fallback',

      debug_has_description: Boolean(
        article.description &&
        String(article.description).trim()
      ),

      debug_items_count: totalItems,
      debug_filtered_items_count: selectedCount,

      debug_original_source: source,
      debug_original_rssUrl: rssUrl,

      debug_article_domain: getDomain(
        article.link
      ),

      debug_rss_domain: getDomain(
        rssUrl
      ),

      debug_filter_time_zone:
        FILTER_TIME_ZONE,

      debug_filter_days:
        FILTER_DAYS,

      debug_filter_today:
        todayKey,

      debug_filter_range_start:
        rangeStartKey,

      debug_article_date: parsedDate
        ? getDateKey(
            parsedDate,
            FILTER_TIME_ZONE
          )
        : ''
    }
  };
}

var output = [];
var allArticles = [];

var currentDateKey = getDateKey(
  new Date(),
  FILTER_TIME_ZONE
);

// FILTER_DAYS = 7 时，起始日期是今天往前 6 天
var rangeStartDateKey = getPreviousDateKey(
  currentDateKey,
  FILTER_DAYS - 1
);

/**
 * 第一步：
 * 解析 RSS 中全部文章。
 */
for (
  var index = 0;
  index < items.length;
  index++
) {
  var item = items[index];

  if (!item) {
    continue;
  }

  var link = getLink(item);
  var title = toText(item.title);

  var descriptionRaw = '';

  if (toText(item.description)) {
    descriptionRaw = toText(
      item.description
    );
  } else if (toText(item.summary)) {
    descriptionRaw = toText(
      item.summary
    );
  } else if (toText(item.content)) {
    descriptionRaw = toText(
      item.content
    );
  }

  var description = cleanHtml(
    descriptionRaw
  );

  var category = getCategory(item);

  var pubDate = '';

  if (toText(item.pubDate)) {
    pubDate = toText(item.pubDate);
  } else if (toText(item.published)) {
    pubDate = toText(item.published);
  } else if (toText(item.updated)) {
    pubDate = toText(item.updated);
  } else if (toText(item.isoDate)) {
    pubDate = toText(item.isoDate);
  } else if (toText(item.date)) {
    pubDate = toText(item.date);
  } else if (toText(item.created)) {
    pubDate = toText(item.created);
  }

  var finalSource = inferSource(
    link,
    rssUrl,
    source
  );

  var parsedPublishDate =
    parsePublishDate(pubDate);

  allArticles.push({
    article_id: makeArticleId(
      link,
      title,
      index
    ),

    title: title,
    description: description,
    link: link,
    url: link,
    category: category,
    pubDate: pubDate,
    source: finalSource,
    rssUrl: rssUrl,

    // 仅用于排序
    _parsedTimestamp: parsedPublishDate
      ? parsedPublishDate.getTime()
      : 0,

    // 日期相同时保留 RSS 原始顺序
    _originalIndex: index
  });
}

/**
 * 第二步：
 * 找出最近 7 天内的文章。
 */
var recentArticles = [];

for (
  var recentIndex = 0;
  recentIndex < allArticles.length;
  recentIndex++
) {
  var recentArticle =
    allArticles[recentIndex];

  if (
    isWithinLastDays(
      recentArticle.pubDate,
      FILTER_TIME_ZONE,
      FILTER_DAYS
    )
  ) {
    recentArticles.push(
      recentArticle
    );
  }
}

/**
 * 排序函数：
 * 发布时间从新到旧。
 * 无法解析日期的文章排在最后。
 */
function sortArticlesByDate(a, b) {
  if (
    b._parsedTimestamp !==
    a._parsedTimestamp
  ) {
    return (
      b._parsedTimestamp -
      a._parsedTimestamp
    );
  }

  return (
    a._originalIndex -
    b._originalIndex
  );
}

/**
 * 第三步：
 * 如果最近 7 天内有文章，
 * 只输出这些文章，最多 20 篇。
 */
if (recentArticles.length > 0) {
  recentArticles.sort(
    sortArticlesByDate
  );

  var recentOutputCount = Math.min(
    recentArticles.length,
    MAX_OUTPUT_COUNT
  );

  for (
    var recentOutputIndex = 0;
    recentOutputIndex < recentOutputCount;
    recentOutputIndex++
  ) {
    output.push(
      buildOutputItem(
        recentArticles[
          recentOutputIndex
        ],
        'last_7_days',
        items.length,
        recentOutputCount,
        currentDateKey,
        rangeStartDateKey
      )
    );
  }

  return output;
}

/**
 * 第四步：
 * 如果最近 7 天没有文章，
 * 输出整个 RSS 中发布时间最近的 20 篇。
 */
allArticles.sort(
  sortArticlesByDate
);

var fallbackOutputCount = Math.min(
  allArticles.length,
  MAX_OUTPUT_COUNT
);

for (
  var fallbackIndex = 0;
  fallbackIndex < fallbackOutputCount;
  fallbackIndex++
) {
  output.push(
    buildOutputItem(
      allArticles[fallbackIndex],
      'latest_fallback',
      items.length,
      fallbackOutputCount,
      currentDateKey,
      rangeStartDateKey
    )
  );
}

/**
 * 第五步：
 * 如果 RSS 完全没有任何文章，
 * 输出一个状态项，避免后续节点不执行。
 */
if (output.length === 0) {
  output.push({
    json: {
      no_articles_available: true,
      status: 'no_articles_available',
      message: 'RSS 中没有可处理的文章',

      article_id: '',
      title: '',
      description: '',
      link: '',
      url: '',
      category: '',
      pubDate: '',
      source: source,
      rssUrl: rssUrl,

      pm_score_prompt: '',

      should_skip_article_processing: true,

      article_filter_mode: 'empty_feed',
      is_recent_date_match: false,
      used_latest_fallback: false,

      debug_items_count: items.length,
      debug_filtered_items_count: 0,

      debug_original_source: source,
      debug_original_rssUrl: rssUrl,

      debug_filter_time_zone:
        FILTER_TIME_ZONE,

      debug_filter_days:
        FILTER_DAYS,

      debug_filter_today:
        currentDateKey,

      debug_filter_range_start:
        rangeStartDateKey
    }
  });
}

return output;

return $input.all().map((item, index) => {
  function cleanJsonString(value) {
    if (typeof value !== 'string') return value;

    return value
      .trim()
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/```$/i, '')
      .trim();
  }

  function parseStage2(rawText) {
    if (!rawText || !String(rawText).trim()) {
      return {
        stage2_parse_error: true,
        stage2_parse_error_message: 'Stage2 返回为空',
        stage2_raw_response: rawText || ''
      };
    }

    try {
      var cleaned = cleanJsonString(rawText);
      return typeof cleaned === 'string' ? JSON.parse(cleaned) : cleaned;
    } catch (e) {
      return {
        stage2_parse_error: true,
        stage2_parse_error_message: e.message,
        stage2_raw_response: rawText
      };
    }
  }

  function safeText(value, fallback) {
    if (fallback === undefined) fallback = '';

    if (value === null || value === undefined) return fallback;

    if (typeof value === 'string') {
      var text = value.trim();
      return text || fallback;
    }

    if (typeof value === 'number' || typeof value === 'boolean') {
      return String(value);
    }

    return fallback;
  }

  function safeArray(value, fallback) {
    if (fallback === undefined) fallback = [];

    if (Array.isArray(value)) {
      var arr = value.filter(function (x) {
        return Boolean(x);
      });

      return arr.length ? arr : fallback;
    }

    if (typeof value === 'string' && value.trim()) {
      return [value.trim()];
    }

    return fallback;
  }

  function scoreToNumber(value) {
    var n = Number(value);
    if (isNaN(n)) return 0;
    return n;
  }

  function getStage2Raw(currentJson) {
    if (typeof currentJson === 'string') return currentJson;

    return (
      currentJson.response ||
      currentJson.output ||
      currentJson.text ||
      currentJson.message ||
      ''
    );
  }

  // 1. 当前 item 是 Stage2 HTTP Request 的输出
  var raw = getStage2Raw(item.json);
  var stage2 = parseStage2(raw);

  // 2. 从名叫 Loop Over Items 的节点，拿当前 loop branch 的那条资料
  var base = {};

  try {
    base = $('Loop Over Items').item.json || {};
  } catch (e) {
    base = {};
  }

  var pmScore = scoreToNumber(
    base.pm_score !== undefined && base.pm_score !== null
      ? base.pm_score
      : base.importance_score
  );

  var title = safeText(
    base.title_cn ||
    base.title ||
    base.original_title ||
    '',
    '未命名文章'
  );

  var description = safeText(
    base.description ||
    base.executive_summary ||
    '',
    '正文信息不足'
  );

  var link = safeText(
    base.link ||
    base.url ||
    base.original_url ||
    '',
    ''
  );

  var category = safeText(
    base.category ||
    '其他',
    '其他'
  );

  var source = safeText(
    base.source ||
    base.feed_source ||
    base.feedTitle ||
    '',
    '未提供'
  );

  var shouldDeepAnalyze =
    base.should_deep_analyze === true ||
    base.should_deep_analyze === 'true' ||
    pmScore >= 4;

  return {
    json: {
      // 一、Loop Over Items 当前 loop branch 的原始/PM 初筛字段
      article_id: base.article_id || link || title,

      title: title,
      description: description,
      url: link,
      category: category,
      pubDate: base.pubDate || base.isoDate || '',
      source: source,

      pm_score: pmScore,
      pm_reason: base.pm_reason || base.importance_reason || '',
      pm_action: base.pm_action || base.reason_to_skip_or_read || '',
      should_deep_analyze: shouldDeepAnalyze,

      // 二、兼容日报节点的旧字段名
      importance_score: base.importance_score !== undefined && base.importance_score !== null
        ? base.importance_score
