    return text || fallback;
  }

  if (typeof value === 'number' || typeof value === 'boolean') {
    return String(value);
  }

  return fallback;
}

function fieldText(value, fallback) {
  if (fallback === undefined) fallback = '正文未披露';

  if (value === null || value === undefined) return fallback;

  if (typeof value === 'string') {
    var text = value.trim();
    return text || fallback;
  }

  if (typeof value === 'number' || typeof value === 'boolean') {
    return String(value);
  }

  if (Array.isArray(value)) {
    var list = value.filter(function (x) {
      return Boolean(x);
    });

    if (!list.length) return fallback;

    var out = [];

    for (var i = 0; i < list.length; i++) {
      var itemText = fieldText(list[i], '');
      if (itemText) out.push(itemText);
    }

    return out.length ? out.join('\n') : fallback;
  }

  if (typeof value === 'object') {
    var evidence = safeText(value.evidence, '');
    var analysis = safeText(value.analysis, '');

    if (evidence && analysis) {
      return '依据：' + evidence + '\n分析：' + analysis;
    }

    if (analysis) return analysis;
    if (evidence) return '依据：' + evidence;

    var parts = [];

    for (var k in value) {
      if (Object.prototype.hasOwnProperty.call(value, k)) {
        var v = value[k];

        if (v === null || v === undefined) continue;
        if (typeof v === 'string' && v.trim() === '') continue;

        parts.push(k + '：' + fieldText(v, ''));
      }
    }

    return parts.length ? parts.join('\n') : fallback;
  }

  return fallback;
}

function oneLine(value, fallback) {
  return fieldText(value, fallback).replace(/\n/g, '；');
}

function formatList(arr) {
  var list = safeArray(arr);

  if (!list.length) return '- 无';

  var out = [];

  for (var i = 0; i < list.length; i++) {
    out.push('- ' + fieldText(list[i], '无'));
  }

  return out.join('\n');
}

function formatInlineList(arr) {
  var list = safeArray(arr);

  if (!list.length) return '无';

  var out = [];

  for (var i = 0; i < list.length; i++) {
    var text = fieldText(list[i], '');
    if (text) out.push(text);
  }

  return out.length ? out.join('、') : '无';
}

function getUrl(a) {
  return safeText(a.url || a.link || a.original_url || '');
}

function getScore(a) {
  var n = Number(
    a.importance_score !== undefined &&
    a.importance_score !== null &&
    a.importance_score !== ''
      ? a.importance_score
      : a.pm_score
  );

  if (isNaN(n)) return 0;
  return n;
}

function scoreLabel(score) {
  var n = Number(score || 0);

  if (n === 5) return '必读';
  if (n === 4) return '值得深读';
  if (n === 3) return '值得记录';
  if (n === 2) return '一般参考';
  if (n === 1) return '低价值';

  return '无关';
}

function getTitle(a) {
  return safeText(
    a.title_cn ||
    a.title ||
    a.original_title ||
    '',
    '未命名文章'
  );
}

function getOriginalSummary(a) {
  return safeText(
    a.executive_summary ||
    a.description ||
    a.summary ||
    '',
    '正文信息不足'
  );
}

function getSummaryCn(a) {
  var meta = a.analysis_meta || {};

  return safeText(
    meta.summary_cn ||
    a.summary_cn ||
    a.description_cn ||
    a.executive_summary_cn ||
    '',
    ''
  );
}

function getDisplaySummary(a) {
  return safeText(
    getSummaryCn(a) ||
    getOriginalSummary(a),
    '正文信息不足'
  );
}

function getReason(a) {
  return safeText(
    a.importance_reason ||
    a.pm_reason ||
    '',
    '未提供'
  );
}

function getAction(a) {
  return safeText(
    a.pm_action ||
    a.reason_to_skip_or_read ||
    a.deep_analyze_reason ||
    '',
    '未提供'
  );
}

function getCategory(a) {
  return safeText(a.category || '其他', '其他');
}

function getSource(a) {
  return safeText(
    a.source ||
    a.feed_source ||
    a.feedTitle ||
    '未提供',
    '未提供'
  );
}

function getPubDate(a) {
  return safeText(
    a.pubDate ||
    a.isoDate ||
    a.published ||
    a.updated ||
    '未提供',
    '未提供'
  );
}

function hasStage2(a) {
  return Boolean(
    a.analysis_meta ||
    a.narrative_report ||
    a.compact_signals ||
    a.pm_actions ||
    a.what_to_watch
  );
}

function isSuspicious(a) {
  if (safeText(a.link_consistency, '正常') === '存疑') return true;

  var meta = a.analysis_meta || {};
  var narrative = a.narrative_report || {};

  var dataQuality = safeText(meta.data_quality, '');
  var caution = safeText(narrative.caution, '');

  if (dataQuality.indexOf('不一致') >= 0) return true;
  if (dataQuality.indexOf('错配') >= 0) return true;
  if (dataQuality.indexOf('存疑') >= 0) return true;
  if (dataQuality.indexOf('人工核查') >= 0) return true;

  if (caution.indexOf('不一致') >= 0) return true;
  if (caution.indexOf('错配') >= 0) return true;
  if (caution.indexOf('存疑') >= 0) return true;
  if (caution.indexOf('人工核查') >= 0) return true;

  return false;
}

function getAnalysisFit(a) {
  var meta = a.analysis_meta || {};

  return safeText(
    meta.analysis_fit ||
    a.analysis_fit ||
    '',
    '未提供'
  );
}

function getEvidenceLevel(a) {
  var meta = a.analysis_meta || {};

  return safeText(
    meta.evidence_level ||
    a.evidence_level ||
    '',
    '未提供'
  );
}

function getDataQuality(a) {
  var meta = a.analysis_meta || {};

  return safeText(
    meta.data_quality ||
    a.data_quality ||
    '',
    '未提供'
  );
}

function getOneSentenceJudgment(a) {
  var meta = a.analysis_meta || {};

  return safeText(
    meta.one_sentence_judgment ||
    a.one_sentence_judgment ||
    '',
    '未提供'
  );
}

function getShouldBeMainReport(a) {
  var meta = a.analysis_meta || {};

  if (meta.should_be_main_report === true) return true;
  if (meta.should_be_main_report === false) return false;

  return getScore(a) >= 3;
}

function getReasonIfNotMainReport(a) {
  var meta = a.analysis_meta || {};

  return safeText(
    meta.reason_if_not_main_report || '',
    '未提供'
  );
}

function cleanArticleForOutput(a) {
  var copy = {};

  for (var k in a) {
    if (Object.prototype.hasOwnProperty.call(a, k)) {
      if (k === 'text') continue;
      if (k === 'prompt_stage2') continue;
      if (k === 'ollama_stage2_body') continue;
      if (k === 'stage2_raw_response') continue;
      if (k === 'debug_raw_stage2_preview') continue;
      if (k.indexOf('debug_') === 0) continue;

      copy[k] = a[k];
    }
  }

  return copy;
}

function countByField(articles, getter) {
  var map = {};

  for (var i = 0; i < articles.length; i++) {
    var key = getter(articles[i]);

    if (!key) key = '未提供';

    if (!map[key]) map[key] = 0;
    map[key]++;
  }

  return map;
}

function renderCountMap(map) {
  var keys = Object.keys(map);

  if (!keys.length) return '- 无';

  keys.sort(function (a, b) {
    return map[b] - map[a];
  });

  var out = [];

  for (var i = 0; i < keys.length; i++) {
    out.push(
      '- ' +
      keys[i] +
      '：' +
      map[keys[i]] +
      ' 篇'
    );
  }

  return out.join('\n');
}

function parsePubDate(value) {
  var text = safeText(value, '');

  if (!text || text === '未提供') return null;

  var date = new Date(text);

  if (isNaN(date.getTime())) return null;

  return date;
}

function formatDateOnly(date) {
  if (!date) return '';

  var year = date.getFullYear();
  var month = date.getMonth() + 1;
  var day = date.getDate();

  return year + '/' + month + '/' + day;
}

function renderSourceDistribution(articles) {
  var sourceMap = {};

  for (var i = 0; i < articles.length; i++) {
    var article = articles[i];
    var source = getSource(article);
    var pubDate = parsePubDate(getPubDate(article));

    if (!sourceMap[source]) {
      sourceMap[source] = {
        count: 0,
        minDate: null,
        maxDate: null
      };
    }

    sourceMap[source].count++;

    if (pubDate) {
      if (
        !sourceMap[source].minDate ||
        pubDate.getTime() < sourceMap[source].minDate.getTime()
      ) {
        sourceMap[source].minDate = pubDate;
      }

      if (
        !sourceMap[source].maxDate ||
        pubDate.getTime() > sourceMap[source].maxDate.getTime()
      ) {
        sourceMap[source].maxDate = pubDate;
      }
    }
  }

  var sources = Object.keys(sourceMap);

  if (!sources.length) return '- 无';

  sources.sort(function (a, b) {
    return sourceMap[b].count - sourceMap[a].count;
  });

  var out = [];

  for (var j = 0; j < sources.length; j++) {
    var sourceName = sources[j];
    var item = sourceMap[sourceName];
    var dateRange = '日期未提供';

    if (item.minDate && item.maxDate) {
      dateRange =
        formatDateOnly(item.minDate) +
        '--' +
        formatDateOnly(item.maxDate);
    }

    out.push(
      '- ' +
      sourceName +
      '：' +
      item.count +
      ' 篇  ' +
      dateRange
    );
  }

  return out.join('\n');
}

function renderTopHighlights(articles) {
  var highlights = [];

  for (var i = 0; i < articles.length; i++) {
    var a = articles[i];
    var score = getScore(a);

    if (score >= 4 || getShouldBeMainReport(a)) {
      highlights.push(a);
    }
  }

  highlights.sort(function (a, b) {
    return getScore(b) - getScore(a);
  });

  if (!highlights.length) {
    return '- 今日暂无明确 4 分以上必读新闻，建议重点看 3 分中与产品路线、Agent、企业落地相关的条目。';
  }

  var out = [];

  for (var j = 0; j < highlights.length; j++) {
    var item = highlights[j];

    out.push(
      '- ' +
      getTitle(item) +
      '｜' +
      getScore(item) +
      '/5｜' +
      getSource(item) +
      '｜' +
      oneLine(
        getOneSentenceJudgment(item),
        getReason(item)
      )
    );
  }

  return out.join('\n');
}

function renderSuspiciousList(articles) {
  var out = [];

  for (var i = 0; i < articles.length; i++) {
    var a = articles[i];

    if (!isSuspicious(a)) continue;

    var meta = a.analysis_meta || {};
    var narrative = a.narrative_report || {};

    out.push(
      '- ' +
      getTitle(a) +
      '｜原因：' +
      oneLine(
        meta.data_quality ||
        narrative.caution ||
        a.link_consistency ||
        '需要人工核查',
        '需要人工核查'
      )
    );
  }

  return out.length
    ? out.join('\n')
    : '- 暂无明显需要人工核查的条目';
}

var sorted = inputArticles.slice();

sorted.sort(function (a, b) {
  var scoreDiff = getScore(b) - getScore(a);

  if (scoreDiff !== 0) return scoreDiff;

  var aMain = getShouldBeMainReport(a) ? 1 : 0;
  var bMain = getShouldBeMainReport(b) ? 1 : 0;

  return bMain - aMain;
});

var highCount = 0;
var recordCount = 0;
var lowCount = 0;
var suspiciousCount = 0;
var stage2Count = 0;
var mainReportCount = 0;

for (var c = 0; c < sorted.length; c++) {
  var score = getScore(sorted[c]);

  if (score >= 4) {
    highCount++;
  } else if (score === 3) {
    recordCount++;
  } else {
    lowCount++;
  }

  if (isSuspicious(sorted[c])) suspiciousCount++;
  if (hasStage2(sorted[c])) stage2Count++;
  if (getShouldBeMainReport(sorted[c])) mainReportCount++;
}

var sourceCountMap = countByField(sorted, function (a) {
  return getSource(a);
});

var categoryCountMap = countByField(sorted, function (a) {
  return getCategory(a);
});

function renderHeader() {
  return (
    '# AI 科技新闻分析日报\n\n' +
    '## 今日概览\n\n' +
    '- 已写入邮件：' + sorted.length + ' 篇\n' +
    '- 深度分析完成：' + stage2Count + ' 篇\n' +
    '- 建议进入主报告：' + mainReportCount + ' 篇\n' +
    '- 重点 / 值得深读：' + highCount + ' 篇\n' +
    '- 值得记录：' + recordCount + ' 篇\n' +
    '- 低优先级 / 一般参考：' + lowCount + ' 篇\n' +
    '- 需要人工核查：' + suspiciousCount + ' 篇\n\n' +

    '## 来源分布\n\n' +
    renderSourceDistribution(sorted) + '\n\n'
  );
}

function renderMetaBlock(a) {
  var score = getScore(a);
  var url = getUrl(a);

  var statusParts = [];

  if (getShouldBeMainReport(a)) {
    statusParts.push('进入主报告');
  } else {
    statusParts.push('不进主报告');
  }

  if (hasStage2(a)) {
    statusParts.push('已深度分析');
  } else {
    statusParts.push('仅初筛');
  }

  if (isSuspicious(a)) {
    statusParts.push('需核查');
  }

  return (
    '- 状态：' + statusParts.join(' / ') + '\n' +
    '- 评分：' + score + ' / 5（' + scoreLabel(score) + '）\n' +
    '- 分析匹配度：' +
    getAnalysisFit(a) +
    '｜证据等级：' +
    getEvidenceLevel(a) +
    '\n' +
    '- 分类：' +
    getCategory(a) +
    '｜次级分类：' +
    formatInlineList(a.secondary_categories) +
    '\n' +
    '- 来源：' +
    getSource(a) +
    '｜发布时间：' +
    getPubDate(a) +
    '\n' +
    '- 链接：' +
    fieldText(url, '无') +
    '\n'
  );
}

function renderStage2Block(a) {
  var meta = a.analysis_meta || {};
  var narrative = a.narrative_report || {};
  var signals = a.compact_signals || {};

  if (!hasStage2(a)) {
    return (
      '**简要判断**\n' +
      getAction(a) +
      '\n'
    );
  }

  return (
    '**一句话判断**\n' +
    fieldText(
      meta.one_sentence_judgment,
      getReason(a)
    ) +
    '\n\n' +

    '- 主报告判断：' +
    fieldText(
      meta.reason_if_not_main_report,
      '未提供'
    ) +
    '\n\n' +

    '**发生了什么**\n' +
    fieldText(
      narrative.overview,
      getDisplaySummary(a)
    ) +
    '\n\n' +

    '**为什么重要**\n' +
    fieldText(
      narrative.why_it_matters,
      fieldText(
        meta.one_sentence_judgment,
        '正文未披露'
      )
    ) +
    '\n\n' +

    '**产品启发**\n' +
    fieldText(
      narrative.product_implication,
      '正文未披露'
    ) +
    '\n\n' +

    '**商业 / 战略信号**\n' +
    fieldText(
      narrative.business_or_strategy_signal,
      '正文未披露'
    ) +
    '\n\n' +

    '**风险与限制**\n' +
    fieldText(
      narrative.risk_and_limits,
      '正文未披露'
    ) +
    '\n\n' +

    '**PM 结论**\n' +
    fieldText(
      narrative.pm_takeaway,
      '正文未披露'
    ) +
    '\n\n' +

    '**关键信号**\n' +
    '- 产品信号：' +
    oneLine(
      signals.product_signal,
      '无明显产品信号'
    ) +
    '\n' +

    '- 竞品 / 生态信号：' +
    oneLine(
      signals.competitive_signal,
      '无明显竞品信号'
    ) +
    '\n' +

    '- 企业采用信号：' +
    oneLine(
      signals.enterprise_adoption_signal,
      '无明显企业采用信号'
    ) +
    '\n' +

    '- Agent / Workflow 信号：' +
    oneLine(
      signals.agent_or_workflow_signal,
      '无明显 Agent 或 Workflow 信号'
    ) +
    '\n' +

    '- 定价 / 分发信号：' +
    oneLine(
      signals.pricing_or_distribution_signal,
      '无明显定价或分发信号'
    ) +
    '\n\n' +

    '**PM 动作建议**\n' +
    formatList(a.pm_actions) +
    '\n\n' +

    '**后续关注**\n' +
    formatList(a.what_to_watch) +
    '\n'
  );
}

function renderArticle(a, index) {
  var summaryCn = getSummaryCn(a);
  var originalSummary = getOriginalSummary(a);

  var summaryBlock = '';

  if (summaryCn) {
    summaryBlock +=
      '**中文摘要**\n' +
      summaryCn +
      '\n\n';
  }

  summaryBlock +=
    '**原始 RSS 摘要**\n' +
    originalSummary +
    '\n\n';

  return (
    '## ' +
    (index + 1) +
    '. ' +
    getTitle(a) +
    '\n\n' +

    renderMetaBlock(a) +
    '\n' +

    '**评分理由**\n' +
    getReason(a) +
    '\n\n' +

    '**初筛动作**\n' +
    getAction(a) +
    '\n\n' +

    summaryBlock +

    renderStage2Block(a)
  );
}

var body = renderHeader();

body += '\n---\n\n# 全部新闻整理\n\n';

var blocks = [];

for (var r = 0; r < sorted.length; r++) {
  blocks.push(renderArticle(sorted[r], r));
}

body += blocks.join('\n\n---\n\n');

var today = new Date().toLocaleDateString('zh-CN');

var outputArticles = [];

for (var oa = 0; oa < sorted.length; oa++) {
  outputArticles.push(
    cleanArticleForOutput(sorted[oa])
  );
}

return [
  {
    json: {
      article_count_raw: inputArticles.length,
      article_count_email: sorted.length,
      stage2_count: stage2Count,
      main_report_count: mainReportCount,
      high_count: highCount,
      record_count: recordCount,
      low_count: lowCount,
      suspicious_count: suspiciousCount,
      source_distribution: sourceCountMap,
      category_distribution: categoryCountMap,
      subject:
        'AI科技新闻分析日报 - ' +
        today +
        ' (' +
        sorted.length +
        '篇，主报告' +
        mainReportCount +
        '篇，重点' +
        highCount +
        '篇，核查' +
        suspiciousCount +
        '篇)',
      body: body,
      articles_all: outputArticles
    }
  }
];
